import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
  cloneElement,
  isValidElement,
} from 'react';
import { createPortal } from 'react-dom';
import type { Placement } from '@arvo/core';
import { filterItems, filterGroups } from '@arvo/core';
import type { ListItemBase, ListGroup } from '@arvo/core';
import type { ArvoPopoverAction } from '../Popover/Popover';
import ArvoPopover from '../Popover/Popover';
import ArvoIconButton from '../IconButton/IconButton';
import ArvoSearch from '../Search/Search';
import { useOverlay } from '../../hooks/useOverlay';
import { useFocusTrap } from '../../hooks/useFocusTrap';
import { usePositioning } from '../../hooks/usePositioning';
import { useListNavigation } from '../../hooks/useListNavigation';
import type { MenuSearchProp } from '../../types/menu-search';
import { normalizeSearch } from '../../types/menu-search';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface MenuTrailingAction {
  id: string;
  icon: string;
  ariaLabel?: string;
  isDisabled?: boolean;
  onClick?: (item: MenuItemData, event: React.MouseEvent) => boolean | void;
  inlinePopover?: MenuInlinePopoverConfig;
  inlineHybridPopover?: MenuInlineHybridPopoverConfig;
}

export interface MenuInlinePopoverConfig {
  title?: string;
  content: React.ReactNode;
  actions?: ArvoPopoverAction[];
  isClosable?: boolean;
  hasBackButton?: boolean;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onBack?: () => void;
}

export interface MenuInlineHybridPopoverConfig {
  title?: string;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onBack?: () => void;
}

export interface MenuItemData extends ListItemBase {
  shortcut?: string;
  destructive?: boolean;
  active?: boolean;
  submenu?: MenuItemData[];
  trailingActions?: MenuTrailingAction[];
  inlinePopover?: MenuInlinePopoverConfig;
  inlineHybridPopover?: MenuInlineHybridPopoverConfig;
}

export interface ArvoActionMenuProps {
  items: MenuItemData[] | ListGroup<MenuItemData>[];
  isLoading?: boolean;
  /** Enable search with defaults (`true`) or pass a config object. */
  search?: MenuSearchProp;
  placement?: 'top-start' | 'top-end' | 'bottom-start' | 'bottom-end'
    | 'left-start' | 'left-end' | 'right-start' | 'right-end' | 'auto';
  maxHeight?: string;
  size?: 'sm' | 'md';
  hasGroupDividers?: boolean;
  trailingActionsVisibility?: 'always' | 'hover';
  submenuTrigger?: 'hover' | 'click';
  closeOnSelect?: boolean;
  isOpen?: boolean;
  defaultOpen?: boolean;
  isDisabled?: boolean;
  trigger: React.ReactElement;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onSelect?: (item: MenuItemData, index: number) => boolean | void;
  onOpenChange?: (isOpen: boolean) => void;
  className?: string;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: MenuItemData[] | ListGroup<MenuItemData>[],
): items is ListGroup<MenuItemData>[] {
  return items.length > 0 && 'items' in items[0];
}

function flattenItems(
  items: MenuItemData[] | ListGroup<MenuItemData>[],
): MenuItemData[] {
  if (isGrouped(items)) {
    return items.flatMap((g) => g.items);
  }
  return items as MenuItemData[];
}

// ---------------------------------------------------------------------------
// Skeleton (Pattern B)
// ---------------------------------------------------------------------------

function MenuSkeleton({ count = 5 }: { count?: number }) {
  return (
    <>
      {Array.from({ length: count }, (_, i) => (
        <div key={i} className="arvo-action-menu__skeleton" aria-hidden="true">
          <div className="arvo-action-menu__skeleton-icon" />
          <div className="arvo-action-menu__skeleton-text" />
        </div>
      ))}
    </>
  );
}

// ---------------------------------------------------------------------------
// Submenu Panel (lightweight nested menu)
// ---------------------------------------------------------------------------

function SubmenuPanel({
  items,
  closeOnSelect,
  onClose,
  onCloseAll,
  onSelect,
  anchorRef,
}: {
  items: MenuItemData[];
  closeOnSelect: boolean;
  onClose: () => void;
  onCloseAll: () => void;
  onSelect: (item: MenuItemData, index: number) => boolean | void;
  anchorRef: React.RefObject<HTMLElement | null>;
}) {
  const panelRef = useRef<HTMLDivElement>(null);

  const enabledItems = useMemo(
    () => items.map((item, i) => ({ item, index: i })).filter(({ item }) => !item.isDisabled),
    [items],
  );

  const [activeIdx, setActiveIdx] = useState(() => {
    return enabledItems.length > 0 ? enabledItems[0].index : -1;
  });

  const { position } = usePositioning({
    anchorRef,
    floatRef: panelRef,
    placement: 'right-start',
    gap: 0,
    enabled: true,
  });

  const handleItemClick = useCallback(
    (item: MenuItemData, index: number) => {
      if (item.isDisabled) return;
      const result = onSelect(item, index);
      if (result !== false && closeOnSelect) onCloseAll();
    },
    [onSelect, closeOnSelect, onCloseAll],
  );

  const focusItem = useCallback(
    (index: number) => {
      setActiveIdx(index);
      const el = panelRef.current?.querySelector(
        `[data-submenu-index="${index}"]`,
      ) as HTMLElement | null;
      el?.focus({ preventScroll: true });
    },
    [],
  );

  const focusFirstEnabled = useCallback(() => {
    if (enabledItems.length > 0) focusItem(enabledItems[0].index);
  }, [enabledItems, focusItem]);

  const focusLastEnabled = useCallback(() => {
    if (enabledItems.length > 0) focusItem(enabledItems[enabledItems.length - 1].index);
  }, [enabledItems, focusItem]);

  // Focus first enabled item when submenu opens
  useEffect(() => {
    if (position) {
      requestAnimationFrame(() => focusFirstEnabled());
    }
  }, [position, focusFirstEnabled]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      const currentEnabledIdx = enabledItems.findIndex(({ index }) => index === activeIdx);

      switch (e.key) {
        case 'ArrowDown': {
          e.preventDefault();
          e.stopPropagation();
          const next = currentEnabledIdx < enabledItems.length - 1 ? currentEnabledIdx + 1 : 0;
          focusItem(enabledItems[next].index);
          break;
        }
        case 'ArrowUp': {
          e.preventDefault();
          e.stopPropagation();
          const prev = currentEnabledIdx > 0 ? currentEnabledIdx - 1 : enabledItems.length - 1;
          focusItem(enabledItems[prev].index);
          break;
        }
        case 'Home': {
          e.preventDefault();
          e.stopPropagation();
          focusFirstEnabled();
          break;
        }
        case 'End': {
          e.preventDefault();
          e.stopPropagation();
          focusLastEnabled();
          break;
        }
        case 'ArrowLeft':
        case 'Escape': {
          e.preventDefault();
          e.stopPropagation();
          onClose();
          break;
        }
        case 'Tab': {
          e.preventDefault();
          e.stopPropagation();
          onCloseAll();
          break;
        }
        case 'Enter':
        case ' ': {
          e.preventDefault();
          e.stopPropagation();
          if (activeIdx >= 0) handleItemClick(items[activeIdx], activeIdx);
          break;
        }
        default:
          break;
      }
    },
    [activeIdx, enabledItems, items, focusItem, focusFirstEnabled, focusLastEnabled, onClose, onCloseAll, handleItemClick],
  );

  const panelClasses = 'arvo-action-menu arvo-action-menu--submenu open';

  const panelStyle: React.CSSProperties = position
    ? { transform: `translate(${position.x}px, ${position.y}px)` }
    : { opacity: 0, visibility: 'hidden' as const, pointerEvents: 'none' as const };

  return createPortal(
    <div
      ref={panelRef}
      className={panelClasses}
      role="menu"
      tabIndex={-1}
      style={panelStyle}
      onKeyDown={handleKeyDown}
    >
      <div className="arvo-action-menu__scroll">
        {items.map((item, i) => (
          <div
            key={item.id}
            className={[
              'arvo-menu-item',
              item.isDisabled && 'is-disabled',
              item.destructive && 'arvo-menu-item--destructive',
              i === activeIdx && 'focused',
            ]
              .filter(Boolean)
              .join(' ')}
            role="menuitem"
            aria-disabled={item.isDisabled || undefined}
            tabIndex={i === activeIdx ? 0 : -1}
            data-submenu-index={i}
            onClick={() => handleItemClick(item, i)}
          >
            {item.icon && (
              <span className={`arvo-menu-item__ico o9con o9con-${item.icon}`} aria-hidden="true" />
            )}
            <div className="arvo-menu-item__txt">
              <span className="arvo-menu-item__lbl">{item.label}</span>
            </div>
          </div>
        ))}
      </div>
    </div>,
    document.body,
  );
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const ArvoActionMenu = forwardRef<HTMLDivElement, ArvoActionMenuProps>(
  function ArvoActionMenu(
    {
      items,
      isLoading = false,
      search,
      placement = 'bottom-start',
      maxHeight,
      hasGroupDividers = true,
      trailingActionsVisibility = 'always',
      submenuTrigger = 'hover',
      closeOnSelect = true,
      isOpen: openProp,
      defaultOpen = false,
      isDisabled = false,
      trigger,
      onOpen,
      onClose,
      onSelect,
      onOpenChange,
      className,
    },
    ref,
  ) {
    const uid = useId();
    const menuId = `arvo-action-menu-${uid}`;

    const searchCfg = useMemo(
      () => normalizeSearch(search),
      [search],
    );

    const panelRef = useRef<HTMLDivElement>(null);
    const triggerRef = useRef<HTMLElement | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const searchWrapperRef = useRef<HTMLDivElement>(null);
    const inlinePanelRef = useRef<HTMLDivElement>(null);

    useImperativeHandle(ref, () => panelRef.current!, []);

    // ── Controlled / Uncontrolled state ──────────────────────────────────
    const isControlled = openProp !== undefined;
    const [internalOpen, setInternalOpen] = useState(defaultOpen);
    const isOpen = isControlled ? openProp! : internalOpen;

    const setOpen = useCallback(
      (next: boolean) => {
        if (!isControlled) setInternalOpen(next);
        onOpenChange?.(next);
      },
      [isControlled, onOpenChange],
    );

    // ── Filter state ────────────────────────────────────────────────────
    const [filterQuery, setFilterQuery] = useState('');

    const filteredItems = useMemo(() => {
      if (!searchCfg || !filterQuery) return items;
      if (isGrouped(items)) {
        return filterGroups(items, { query: filterQuery });
      }
      return filterItems(items as MenuItemData[], { query: filterQuery });
    }, [items, searchCfg, filterQuery]);

    const flatItems = useMemo(() => flattenItems(filteredItems), [filteredItems]);

    const totalItemCount = useMemo(() => flattenItems(items).length, [items]);

    useEffect(() => {
      if (searchCfg && filterQuery) {
        searchCfg.onFilter?.(filterQuery, flatItems.length);
      }
    }, [searchCfg, filterQuery, flatItems.length]);

    // ── Submenu state ─────────────────────────────────────────────────
    const [openSubmenuId, setOpenSubmenuId] = useState<string | null>(null);
    const submenuTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const itemRefsMap = useRef<Map<string, HTMLElement>>(new Map());

    // ── Inline popover state ────────────────────────────────────────────
    const [inlinePanel, setInlinePanel] = useState<{
      config: MenuInlinePopoverConfig;
      sourceItem: MenuItemData;
    } | null>(null);

    const closeInlinePanel = useCallback(() => {
      if (!inlinePanel) return;
      if (inlinePanel.config.onClose?.() === false) return;
      setInlinePanel(null);
    }, [inlinePanel]);

    const openInlinePanel = useCallback(
      (config: MenuInlinePopoverConfig, sourceItem: MenuItemData) => {
        if (config.onOpen?.() === false) return;
        setInlinePanel({ config, sourceItem });
      },
      [],
    );

    // ── Overlay hub ──────────────────────────────────────────────────────
    const overlay = useOverlay();

    // ── Open / Close handlers ────────────────────────────────────────────
    const handleOpen = useCallback(() => {
      if (isOpen || isDisabled) return;
      if (onOpen?.() === false) return;

      setOpen(true);

      if (panelRef.current) {
        overlay.open({
          id: menuId,
          type: 'action-menu',
          element: panelRef.current,
          triggerElement: triggerRef.current ?? undefined,
          priority: 20,
          config: { autoCloseOnOutsideClick: true },
        });
      }

      triggerRef.current?.dispatchEvent(
        new CustomEvent('action-menu:open', { bubbles: true, cancelable: true }),
      );
    }, [isOpen, isDisabled, onOpen, setOpen, overlay, menuId]);

    const handleClose = useCallback(() => {
      if (!isOpen) return;
      if (onClose?.() === false) return;

      setOpen(false);
      setFilterQuery('');
      setInlinePanel(null);
      setOpenSubmenuId(null);
      overlay.close(menuId);
      triggerRef.current?.focus({ preventScroll: true });
      triggerRef.current?.dispatchEvent(
        new CustomEvent('action-menu:close', { bubbles: true, cancelable: true }),
      );
    }, [isOpen, onClose, setOpen, overlay, menuId]);

    const toggleOpen = useCallback(() => {
      if (isOpen) handleClose();
      else handleOpen();
    }, [isOpen, handleOpen, handleClose]);

    // ── Register panel with overlay hub when it opens ────────────────────
    useEffect(() => {
      if (!isOpen || !panelRef.current) return;
      overlay.open({
        id: menuId,
        type: 'action-menu',
        element: panelRef.current,
        triggerElement: triggerRef.current ?? undefined,
        priority: 20,
        config: { autoCloseOnOutsideClick: true },
        onClose: handleClose,
      });
      return () => { overlay.close(menuId); };
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Positioning ──────────────────────────────────────────────────────
    const { position } = usePositioning({
      anchorRef: triggerRef,
      floatRef: panelRef,
      placement: placement as Placement,
      gap: 2,
      enabled: isOpen,
    });

    const positioned = !!position;

    // ── Focus trap ───────────────────────────────────────────────────────
    useFocusTrap(inlinePanel ? inlinePanelRef : panelRef, {
      active: isOpen && positioned && !isLoading,
      escapeDeactivates: false,
      returnFocusOnDeactivate: true,
      allowOutsideClick: true,
    });

    // ── List navigation ──────────────────────────────────────────────────
    const searchFocused = useRef(false);
    const keyboardActiveRef = useRef(false);

    const handleItemSelect = useCallback(
      (item: ListItemBase, index: number) => {
        const menuItem = item as MenuItemData;
        if (menuItem.isDisabled) return;

        if (menuItem.submenu) {
          setOpenSubmenuId(menuItem.id);
          return;
        }

        if (menuItem.inlinePopover) {
          openInlinePanel(menuItem.inlinePopover, menuItem);
          return;
        }

        const result = onSelect?.(menuItem, index);

        triggerRef.current?.dispatchEvent(
          new CustomEvent('action-menu:select', {
            bubbles: true,
            cancelable: true,
            detail: { item: menuItem, index },
          }),
        );

        if (result !== false && closeOnSelect) {
          handleClose();
        }
      },
      [onSelect, closeOnSelect, handleClose, openInlinePanel],
    );

    const scrollToIndex = useCallback(
      (index: number) => {
        keyboardActiveRef.current = true;
        const el = scrollRef.current?.querySelector(
          `[data-index="${index}"]`,
        ) as HTMLElement | null;
        if (el) {
          el.scrollIntoView({ block: 'nearest' });
          el.focus({ preventScroll: true });
        }
      },
      [],
    );

    const { activeIndex, setActiveIndex, handleKeyDown: navKeyDown } =
      useListNavigation({
        items: flatItems,
        onSelect: handleItemSelect,
        onEscape: () => {
          if (inlinePanel) {
            closeInlinePanel();
          } else {
            handleClose();
          }
        },
        wrap: true,
        enabled: isOpen && positioned && !isLoading && !searchFocused.current && !inlinePanel,
        scrollToIndex,
      });

    // Reset active index when items change or menu opens
    useEffect(() => {
      if (isOpen) {
        keyboardActiveRef.current = false;
        setActiveIndex(0);
      }
    }, [isOpen, flatItems, setActiveIndex]);

    // Close submenu when active index moves away (click mode only;
    // hover mode handles this via onMouseEnter/onMouseLeave timers)
    useEffect(() => {
      if (submenuTrigger === 'click' && openSubmenuId) {
        const activeItem = flatItems[activeIndex];
        if (activeItem?.id !== openSubmenuId) {
          setOpenSubmenuId(null);
        }
      }
    }, [activeIndex, flatItems, openSubmenuId, submenuTrigger]);

    // Focus the search input or first item when menu opens
    useEffect(() => {
      if (!isOpen || !positioned) return;
      requestAnimationFrame(() => {
        if (searchCfg && searchWrapperRef.current) {
          const input = searchWrapperRef.current.querySelector('input');
          input?.focus();
        }
      });
    }, [isOpen, positioned, searchCfg]);

    // ── Escape key ───────────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen) return;
      const onKeyDown = (e: KeyboardEvent) => {
        if (e.key === 'Escape') {
          // When a submenu is open, let the submenu handle Escape
          if (openSubmenuId) return;

          e.stopPropagation();
          if (inlinePanel) {
            closeInlinePanel();
          } else {
            handleClose();
          }
        }
      };
      document.addEventListener('keydown', onKeyDown, true);
      return () => document.removeEventListener('keydown', onKeyDown, true);
    }, [isOpen, handleClose, inlinePanel, closeInlinePanel, openSubmenuId]);

    // ── Outside click ────────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen) return;
      const onPointerDown = (e: PointerEvent) => {
        const target = e.target as Node;
        if (panelRef.current?.contains(target)) return;
        if (triggerRef.current?.contains(target)) return;
        handleClose();
      };
      document.addEventListener('pointerdown', onPointerDown, true);
      return () => document.removeEventListener('pointerdown', onPointerDown, true);
    }, [isOpen, handleClose]);

    // ── Trigger click handler ────────────────────────────────────────────
    const handleTriggerClick = useCallback(
      (e: React.MouseEvent) => {
        e.preventDefault();
        toggleOpen();
      },
      [toggleOpen],
    );

    // ── Item click handler ───────────────────────────────────────────────
    const handleItemClick = useCallback(
      (item: MenuItemData, flatIndex: number) => {
        if (item.isDisabled || isLoading) return;
        setActiveIndex(flatIndex);
        handleItemSelect(item, flatIndex);
      },
      [isLoading, setActiveIndex, handleItemSelect],
    );

    // ── Trailing action click handler ────────────────────────────────────
    const handleTrailingActionClick = useCallback(
      (action: MenuTrailingAction, item: MenuItemData, e: React.MouseEvent) => {
        e.stopPropagation();

        if (action.inlinePopover) {
          openInlinePanel(action.inlinePopover, item);
          return;
        }

        const result = action.onClick?.(item, e);
        if (result !== false && closeOnSelect) {
          handleClose();
        }
      },
      [closeOnSelect, handleClose, openInlinePanel],
    );

    // ── Panel keyboard handler ───────────────────────────────────────────
    const handlePanelKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        if (isLoading) return;

        // Forward to list navigation for arrow/home/end/typeahead
        if (!searchFocused.current && !inlinePanel) {
          navKeyDown(e);
        }

        // ArrowRight: open submenu or focus trailing action
        if (e.key === 'ArrowRight' && !inlinePanel) {
          const activeItem = flatItems[activeIndex];
          if (activeItem?.submenu) {
            e.preventDefault();
            setOpenSubmenuId(activeItem.id);
            return;
          }
          const activeEl = scrollRef.current?.querySelector(
            `[data-index="${activeIndex}"] .arvo-menu-item__actions button`,
          ) as HTMLElement | null;
          if (activeEl) {
            e.preventDefault();
            activeEl.focus();
          }
        }
      },
      [isLoading, navKeyDown, inlinePanel, flatItems, activeIndex],
    );

    // ── Search handlers (ArvoSearch callbacks) ────────────────────────────
    const handleFilterSearch = useCallback(
      (value: string) => {
        setFilterQuery(value);
        setActiveIndex(0);
      },
      [setActiveIndex],
    );

    const handleFilterClear = useCallback(() => {
      setFilterQuery('');
      setActiveIndex(0);
      searchCfg?.onClear?.();
    }, [setActiveIndex, searchCfg]);

    const handleSearchFocus = useCallback(() => {
      searchFocused.current = true;
    }, []);

    const handleSearchBlur = useCallback(() => {
      searchFocused.current = false;
    }, []);

    const handleSearchWrapperKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLDivElement>) => {
        if (e.key === 'ArrowDown') {
          e.preventDefault();
          searchFocused.current = false;
          const firstItem = scrollRef.current?.querySelector(
            '[role="menuitem"]',
          ) as HTMLElement | null;
          firstItem?.focus();
          setActiveIndex(0);
        } else if (e.key === 'Escape' && !filterQuery) {
          e.stopPropagation();
          handleClose();
        }
      },
      [setActiveIndex, handleClose, filterQuery],
    );

    // ── Classes ──────────────────────────────────────────────────────────
    const panelClasses = [
      'arvo-action-menu',
      isOpen && 'open',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Style ────────────────────────────────────────────────────────────
    const panelStyle: React.CSSProperties = {
      ...(position
        ? { transform: `translate(${position.x}px, ${position.y}px)` }
        : {}),
      ...(maxHeight
        ? ({ '--arvo-action-menu-max-height': maxHeight } as React.CSSProperties)
        : {}),
      ...(!positioned ? { opacity: 0, pointerEvents: 'none' as const } : {}),
    };

    // ── Item rendering ───────────────────────────────────────────────────
    const renderTrailing = (item: MenuItemData) => {
      const parts: React.ReactNode[] = [];

      if (item.shortcut) {
        parts.push(
          <span key="shortcut" className="arvo-menu-item__shortcut">
            {item.shortcut}
          </span>,
        );
      }

      if (item.submenu) {
        parts.push(
          <span
            key="submenu"
            className="arvo-menu-item__submenu o9con o9con-angle-right"
            aria-hidden="true"
          />,
        );
      }

      if (item.trailingActions?.length) {
        parts.push(
          <div key="actions" className="arvo-menu-item__actions">
            {item.trailingActions.map((action) => (
              <ArvoIconButton
                key={action.id}
                icon={action.icon}
                variant="tertiary"
                size="sm"
                tooltip={action.ariaLabel ?? action.id}
                aria-label={action.ariaLabel}
                isDisabled={item.isDisabled || isLoading || action.isDisabled}
                onClick={(e) => handleTrailingActionClick(action, item, e)}
              />
            ))}
          </div>,
        );
      }

      if (parts.length === 0) return null;
      return <div className="arvo-menu-item__trailing">{parts}</div>;
    };

    const handleItemMouseEnter = useCallback(
      (item: MenuItemData, flatIndex: number) => {
        keyboardActiveRef.current = false;
        setActiveIndex(flatIndex);

        if (submenuTrigger === 'hover') {
          if (submenuTimerRef.current) {
            clearTimeout(submenuTimerRef.current);
            submenuTimerRef.current = null;
          }

          if (item.submenu && !item.isDisabled) {
            submenuTimerRef.current = setTimeout(() => {
              setOpenSubmenuId(item.id);
            }, 200);
          } else {
            setOpenSubmenuId(null);
          }
        }
      },
      [setActiveIndex, submenuTrigger],
    );

    const handleItemMouseLeave = useCallback(
      (item: MenuItemData) => {
        if (submenuTrigger === 'hover' && item.submenu) {
          if (submenuTimerRef.current) {
            clearTimeout(submenuTimerRef.current);
            submenuTimerRef.current = null;
          }
        }
      },
      [submenuTrigger],
    );

    // Clean up submenu timer on unmount
    useEffect(() => {
      return () => {
        if (submenuTimerRef.current) {
          clearTimeout(submenuTimerRef.current);
        }
      };
    }, []);

    const setItemRef = useCallback(
      (id: string, node: HTMLElement | null) => {
        if (node) {
          itemRefsMap.current.set(id, node);
        } else {
          itemRefsMap.current.delete(id);
        }
      },
      [],
    );

    const renderItem = (item: MenuItemData, flatIndex: number) => {
      const itemClasses = [
        'arvo-menu-item',
        item.secondaryLabel && 'arvo-menu-item--multi-line',
        item.destructive && 'arvo-menu-item--destructive',
        trailingActionsVisibility === 'hover' &&
          item.trailingActions?.length &&
          'arvo-menu-item--actions-on-hover',
        item.isDisabled && 'is-disabled',
        flatIndex === activeIndex && keyboardActiveRef.current && 'focused',
        item.active && 'active',
      ]
        .filter(Boolean)
        .join(' ');

      const submenuOpen = item.submenu && openSubmenuId === item.id;

      return (
        <div key={item.id} style={{ position: 'relative' }}>
          <div
            ref={(node) => setItemRef(item.id, node)}
            className={itemClasses}
            role="menuitem"
            aria-disabled={item.isDisabled || undefined}
            aria-haspopup={item.submenu ? 'menu' : undefined}
            aria-expanded={item.submenu ? !!submenuOpen : undefined}
            tabIndex={flatIndex === activeIndex ? 0 : -1}
            data-index={flatIndex}
            onClick={() => handleItemClick(item, flatIndex)}
            onMouseEnter={() => handleItemMouseEnter(item, flatIndex)}
            onMouseLeave={() => handleItemMouseLeave(item)}
          >
            {item.icon && (
              <span className={`arvo-menu-item__ico o9con o9con-${item.icon}`} aria-hidden="true" />
            )}
            {item.avatar && (
              <img
                className="arvo-menu-item__avatar"
                src={item.avatar}
                alt=""
              />
            )}
            <div className="arvo-menu-item__txt">
              <span className="arvo-menu-item__lbl">{item.label}</span>
              {item.secondaryLabel && (
                <span className="arvo-menu-item__secondary">
                  {item.secondaryLabel}
                </span>
              )}
            </div>
            {renderTrailing(item)}
          </div>
          {submenuOpen && (
            <SubmenuPanel
              items={item.submenu!}
              closeOnSelect={closeOnSelect}
              onClose={() => {
                setOpenSubmenuId(null);
                const parentEl = itemRefsMap.current.get(item.id);
                parentEl?.focus({ preventScroll: true });
              }}
              onCloseAll={handleClose}
              onSelect={(subItem, subIndex) => {
                const result = onSelect?.(subItem, subIndex);
                if (result !== false && closeOnSelect) handleClose();
                return false;
              }}
              anchorRef={{ current: itemRefsMap.current.get(item.id) ?? null }}
            />
          )}
        </div>
      );
    };

    // ── Content rendering (flat vs grouped) ──────────────────────────────
    const renderContent = () => {
      if (isLoading) {
        return <MenuSkeleton />;
      }

      if (flatItems.length === 0) {
        return (
          <div className="arvo-action-menu__empty" role="status">
            No results
          </div>
        );
      }

      if (isGrouped(filteredItems)) {
        let flatIndex = 0;
        return (filteredItems as ListGroup<MenuItemData>[]).map(
          (group, groupIdx) => (
            <div key={group.id} role="group" aria-label={group.label}>
              {groupIdx > 0 && hasGroupDividers && (
                <div
                  className="arvo-action-menu__divider"
                  role="separator"
                />
              )}
              {group.label && (
                <div className="arvo-action-menu__hdr">{group.label}</div>
              )}
              {group.items.map((item) => {
                const node = renderItem(item, flatIndex);
                flatIndex++;
                return node;
              })}
            </div>
          ),
        );
      }

      return (filteredItems as MenuItemData[]).map((item, i) =>
        renderItem(item, i),
      );
    };

    // ── Inline panel rendering ───────────────────────────────────────────
    const renderInlinePanel = () => {
      if (!inlinePanel) return null;
      const { config } = inlinePanel;

      return (
        <div
          ref={inlinePanelRef}
          className="arvo-action-menu__inline-panel open"
        >
          <ArvoPopover
            isInline
            variant="edge"
            title={config.title}
            hasHeader={!!(config.title || config.hasBackButton !== false || config.isClosable !== false)}
            isClosable={config.isClosable !== false}
            hasBackButton={config.hasBackButton !== false}
            onBack={() => {
              config.onBack?.();
              closeInlinePanel();
            }}
            onClose={() => {
              closeInlinePanel();
            }}
            actions={config.actions}
            isOpen
            isInteractive
          >
            {config.content}
          </ArvoPopover>
        </div>
      );
    };

    // ── Trigger cloning ──────────────────────────────────────────────────
    const clonedTrigger = isValidElement(trigger)
      ? cloneElement(trigger as React.ReactElement<Record<string, unknown>>, {
          ref: (node: HTMLElement | null) => {
            triggerRef.current = node;
            // Forward ref from trigger if it has one
            const triggerEl = trigger as React.ReactElement<Record<string, unknown>> & {
              ref?: React.Ref<HTMLElement>;
            };
            const originalRef = triggerEl.ref;
            if (typeof originalRef === 'function') {
              originalRef(node);
            } else if (originalRef && typeof originalRef === 'object') {
              (originalRef as React.MutableRefObject<HTMLElement | null>).current = node;
            }
          },
          'aria-expanded': isOpen,
          'aria-haspopup': 'menu' as const,
          'aria-controls': menuId,
          onClick: handleTriggerClick,
          isDisabled: isDisabled || (trigger.props as Record<string, unknown>).isDisabled,
        })
      : trigger;

    // ── Panel ────────────────────────────────────────────────────────────
    const panel = isOpen
      ? createPortal(
          <div
            ref={panelRef}
            id={menuId}
            className={panelClasses}
            role="menu"
            aria-busy={isLoading || undefined}
            tabIndex={-1}
            style={
              Object.keys(panelStyle).length > 0 ? panelStyle : undefined
            }
            onKeyDown={handlePanelKeyDown}
          >
            {searchCfg && !isLoading && (
              <div
                ref={searchWrapperRef}
                className={[
                  'arvo-action-menu__search',
                  searchCfg.className,
                ].filter(Boolean).join(' ')}
                onKeyDown={handleSearchWrapperKeyDown}
              >
                <ArvoSearch
                  variant="filter"
                  value={filterQuery}
                  placeholder={searchCfg.placeholder}
                  searchMode={searchCfg.searchMode}
                  minChars={searchCfg.minChars}
                  isClearable={searchCfg.isClearable}
                  shortcut={searchCfg.shortcut}
                  errorMsg={searchCfg.errorMsg}
                  errorDisplay="tooltip"
                  counter={
                    searchCfg.counter && filterQuery
                      ? { current: flatItems.length, total: totalItemCount }
                      : null
                  }
                  onSearch={handleFilterSearch}
                  onClear={handleFilterClear}
                  onFocus={handleSearchFocus}
                  onBlur={handleSearchBlur}
                  isDisabled={isDisabled}
                  aria-label="Filter menu items"
                />
              </div>
            )}
            <div ref={scrollRef} className="arvo-action-menu__scroll">
              {renderContent()}
            </div>
            {renderInlinePanel()}
          </div>,
          document.body,
        )
      : null;

    return (
      <>
        {clonedTrigger}
        {panel}
      </>
    );
  },
);

export { ArvoActionMenu };
export default ArvoActionMenu;
